function showTab(e){document.querySelectorAll(".tab-pane").forEach(e=>{e.classList.remove("active")});document.querySelectorAll(".tab-btn").forEach(e=>{e.classList.remove("active")});const t=document.getElementById(e);t&&t.classList.add("active");const o=document.querySelector(`.tab-btn[onclick="showTab('${e}')"]`);o&&o.classList.add("active")}document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("back-to-top");e&&(window.addEventListener("scroll",()=>{document.body.scrollTop>300||document.documentElement.scrollTop>300?e.style.display="block":e.style.display="none"}),e.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})}));const t=document.getElementById("article-select");t&&t.addEventListener("change",function(){const e=this.value;if(e){const t=document.querySelector(e);t?(t.scrollIntoView({behavior:"smooth"}),t.classList.add("highlight"),setTimeout(()=>{t.classList.remove("highlight")},2e3)):console.error("Élément cible non trouvé !")}}),document.querySelectorAll(".reserve-btn").forEach(function(e){e.addEventListener("click",function(){const t=e.getAttribute("data-url");t&&t.startsWith("https://www.boxtal.com/")&&window.open(t,"_blank","noopener")})})});